/// Transform: deduplicate
pub fn transform_deduplicate_cases(
    df: polars::prelude::LazyFrame,
) -> anyhow::Result<polars::prelude::LazyFrame> {
    use polars::prelude::*;
    tracing::info!(stage = "deduplicate-cases", "Deduplicating records");
    let subset_strs: &[&str] = &["case_id", "drug_name", "adverse_event"];
    let deduped = if subset_strs.is_empty() {
        df.unique_stable(None, UniqueKeepStrategy::First)
    } else {
        let subset: Vec<PlSmallStr> = subset_strs
            .iter()
            .map(|&s| PlSmallStr::from_static(s))
            .collect();
        df.unique_stable(Some(subset), UniqueKeepStrategy::First)
    };
    Ok(deduped)
}
/// Transform: PRR signal detection
/// Computes Proportional Reporting Ratio for pharmacovigilance.
pub fn transform_prr_detection(
    df: polars::prelude::LazyFrame,
) -> anyhow::Result<polars::prelude::LazyFrame> {
    use polars::prelude::*;
    tracing::info!(stage = "prr-detection", "Running PRR signal detection");
    let drug_col = "drug_name";
    let event_col = "adverse_event";
    let case_col = "case_id";
    let prr_threshold = 2f64;
    let chi_sq_threshold = 4f64;
    let min_cases = 3u32 as u32;
    let collected = df.clone().collect()?;
    let total_cases = collected.column(case_col)?.n_unique()? as f64;
    let drug_event_counts = df
        .clone()
        .group_by([col(drug_col), col(event_col)])
        .agg([col(case_col).n_unique().alias("a")]);
    let drug_totals = df
        .clone()
        .group_by([col(drug_col)])
        .agg([col(case_col).n_unique().alias("drug_total")]);
    let event_totals = df
        .clone()
        .group_by([col(event_col)])
        .agg([col(case_col).n_unique().alias("event_total")]);
    let with_drug_totals = drug_event_counts
        .join(
            drug_totals,
            [col(drug_col)],
            [col(drug_col)],
            JoinArgs::new(JoinType::Left),
        );
    let with_all_totals = with_drug_totals
        .join(
            event_totals,
            [col(event_col)],
            [col(event_col)],
            JoinArgs::new(JoinType::Left),
        );
    let total = lit(total_cases);
    let result = with_all_totals
        .with_columns([
            (col("drug_total") - col("a")).alias("b"),
            (col("event_total") - col("a")).alias("c"),
        ])
        .with_columns([(total.clone() - col("a") - col("b") - col("c")).alias("d")])
        .with_columns([
            ((col("a").cast(DataType::Float64)
                / (col("a") + col("b")).cast(DataType::Float64))
                / (col("c").cast(DataType::Float64)
                    / (col("c") + col("d")).cast(DataType::Float64)))
                .alias("prr"),
        ])
        .with_columns([
            {
                let ad = col("a").cast(DataType::Float64)
                    * col("d").cast(DataType::Float64);
                let bc = col("b").cast(DataType::Float64)
                    * col("c").cast(DataType::Float64);
                let n = total.clone();
                let ab = (col("a") + col("b")).cast(DataType::Float64);
                let cd = (col("c") + col("d")).cast(DataType::Float64);
                let ac = (col("a") + col("c")).cast(DataType::Float64);
                let bd = (col("b") + col("d")).cast(DataType::Float64);
                let diff = ad - bc;
                let numerator = diff.clone() * diff;
                let denominator = ab * cd * ac * bd;
                (numerator * n / denominator).alias("chi_squared")
            },
        ])
        .with_columns([
            (col("prr")
                .gt(lit(prr_threshold))
                .and(col("chi_squared").gt(lit(chi_sq_threshold)))
                .and(col("a").gt(lit(min_cases))))
                .alias("is_signal"),
        ])
        .filter(col("a").gt(lit(min_cases)));
    Ok(result)
}
