/// Sink: Parquet file output
/// Path template: #path_template
pub fn sink_parquet_archive(df: polars::prelude::LazyFrame) -> anyhow::Result<u64> {
    use polars::prelude::*;
    use anyhow::Context;
    tracing::info!(
        stage = "parquet-archive", path_template = "archive/signals-%Y%m%d.parquet",
        compression = stringify!(ParquetCompression::Zstd(None)), row_group_size =
        1000000u32, "Writing to Parquet"
    );
    let mut output_df = df
        .collect()
        .context("Failed to collect DataFrame for Parquet sink")?;
    let row_count = output_df.height() as u64;
    if row_count == 0 {
        tracing::warn!(stage = "parquet-archive", "No rows to write to Parquet");
        return Ok(0);
    }
    let path = chrono::Utc::now().format("archive/signals-%Y%m%d.parquet").to_string();
    if let Some(parent) = std::path::Path::new(&path).parent() {
        std::fs::create_dir_all(parent)
            .with_context(|| {
                format!("Failed to create directory: {}", parent.display())
            })?;
    }
    let file = std::fs::File::create(&path)
        .with_context(|| format!("Failed to create Parquet file: {}", path))?;
    ParquetWriter::new(file)
        .with_compression(ParquetCompression::Zstd(None))
        .with_row_group_size(Some(1000000u32 as usize))
        .finish(&mut output_df)
        .with_context(|| format!("Failed to write Parquet file: {}", path))?;
    tracing::info!(
        stage = "parquet-archive", path = % path, rows = row_count,
        "Parquet write complete"
    );
    Ok(row_count)
}
